export const siteData = { site, stats, destinations, tourStyles, itineraries, guides, species, testimonials, moments } as const

export type Destination = typeof destinations[number]
export type TourStyle = typeof tourStyles[number]
export type Itinerary = typeof itineraries[number]
export type Guide = typeof guides[number]
export type Species = typeof species[number]
export type Testimonial = typeof testimonials[number]
export type Moment = typeof moments[number]
